class Solution:
    def nthUglyNumber(self, n: int) -> int:
        dp = [1] * n
        i2 = i3 = i5 = 0
        for i in range(1, n):
            next2 = dp[i2] * 2
            next3 = dp[i3] * 3
            next5 = dp[i5] * 5
            min_val = min(next2, next3, next5)
            dp[i] = min_val
            if min_val == next2:
                i2 += 1
            if min_val == next3:
                i3 += 1
            if min_val == next5:
                i5 += 1
        return dp[-1]

